-- See /tmp/part1.sql — payload inlined below
-- B1-fix3-prep Part 1: schema delta + UPSERT 70 sub-categories
-- Idempotent. Preserves existing IDs via ON CONFLICT (type, normalized_name).

-- STEP 1: schema delta
ALTER TABLE public.ontology_categories
  ADD COLUMN IF NOT EXISTS keywords                  text[] NOT NULL DEFAULT '{}',
  ADD COLUMN IF NOT EXISTS example_entries           text[] NOT NULL DEFAULT '{}',
  ADD COLUMN IF NOT EXISTS co_occurring_category_ids uuid[] NOT NULL DEFAULT '{}';

CREATE UNIQUE INDEX IF NOT EXISTS ontology_categories_type_name_uk
  ON public.ontology_categories(type, normalized_name);

-- STEP 2: UPSERT 70 sub-categories
ON CONFLICT (type, normalized_name) DO UPDATE
  SET description     = EXCLUDED.description,
      keywords        = EXCLUDED.keywords,
      example_entries = EXCLUDED.example_entries,
      updated_at      = now();

-- Post-check: 15 capability rows present (sample of 70)
DO $post$
DECLARE v_missing int;
BEGIN
  WITH expected(type, normalized_name) AS (
    SELECT type, normalized_name FROM (VALUES
      ('capability','Business & Governance'),('capability','C4ISR, Communications & PNT'),
      ('capability','Cybersecurity'),('capability','Electronic Warfare'),
      ('capability','Energy & Critical Infrastructure'),('capability','Logistics, Supply Chain & Mobility'),
      ('capability','Manufacturing & Engineering'),('capability','Maritime & Subsea'),
      ('capability','Platforms (Air, Land, Sea, Unmanned)'),('capability','Preparedness, Response & Medical'),
      ('capability','Sensors & Detection'),('capability','Software, Systems & Integration'),
      ('capability','Space'),('capability','Training & Simulation'),('capability','Weapons & Munitions')
    ) AS t(type, normalized_name)
  )
  SELECT count(*) INTO v_missing FROM expected e
  LEFT JOIN public.ontology_categories oc
    ON oc.type = e.type AND oc.normalized_name = e.normalized_name
  WHERE oc.id IS NULL;
  IF v_missing > 0 THEN
    RAISE EXCEPTION 'Part 1 post-check FAIL: % expected capability rows missing', v_missing;
  END IF;
END $post$;